var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"2번 구역의 마지막 장소… 도착했습니다.","JPN":"2番エリアの最後の場所に……到着しました。","ENG":"Arrived... at the last location in Sector 2.","TWN":"第二區域的最後一個地點……到了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여긴, 언니의 집이네요.","JPN":"ここは、姉さんのお家ですね。","ENG":"This is Sis's house.","TWN":"這裡是……姊姊的家。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"지금은 잔해만 남은 폐허일 뿐이지만 말이지.","JPN":"今は残骸だけの廃墟だけどね。","ENG":"It's just rubble now, nothing more.","TWN":"現在只剩下一片廢墟了。"},"stage":{"bg":"ANIV2_03-2","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"범인은 반드시 사건 현장에 돌아온다는 말이 있죠.","JPN":"犯人は必ず事件現場に戻ってくるという言葉があります。","ENG":"There's a saying that a criminal always returns to the scene of the crime.","TWN":"罪犯一定會回到案發現場，這句話，"},"stage":{"bg":"ANIV2_03-2","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 말이 침식체한테도 적용되는진, 지금부터 알아봐야겠지만요.","JPN":"それが侵食体にも該当するかは、今から確認する必要がありますが。","ENG":"We'll see if that applies to a C.O. too.","TWN":"不知道對侵蝕體是否同樣適用，就讓我們試試看吧。"},"stage":{"bg":"ANIV2_03-2","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"미량의 침식파가 감지되고 있어요.","JPN":"微量の侵食波が感知されています。","ENG":"A small trace of Corruption ray is being detected.","TWN":"探測到了微量侵蝕波。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"침식체일까요?","JPN":"侵食体でしょうか？","ENG":"Could it be a C.O.?","TWN":"是侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"온전한 침식체라기엔 강도가 약해요. 아마 이 거대 식물에 붙어있다는 침식 바이러스를 감지한 거겠죠.","JPN":"完全な侵食体にしては強度が弱すぎます。多分、この巨大な植物についているという侵食ウイルスを感知したのでしょう。","ENG":"The strength is weak for it to be a C.O. It's likely because of the Corruption virus attached to this large plant.","TWN":"不像，強度太弱了，可能只是這株巨型植物上附著的侵蝕病毒。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"잎이 붙은 채로 시들었어요.","JPN":"葉が残ったまま枯れています。","ENG":"The leaves have withered while still attached.","TWN":"葉子還連著枝幹就已經枯萎了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"물이 부족했던 거라면, 이파리가 먼저 떨어졌을 텐데…","JPN":"水が足りないなら、先に葉が落ちるはずなのに……","ENG":"If it was just a lack of water, the leaves would have fallen first...","TWN":"如果是缺水導致的，葉子應該會先掉落才對……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"양분의 문제가 아닐 거야. 살아있는 것의 생명력을 빼앗는 침식 특유의 성질 때문이지.","JPN":"栄養の問題ではない。生きているものの生命力を奪うのは侵食特有の性質だ。","ENG":"It's not a nutrition issue. The unique nature of the Corruption steals the life force from the living.","TWN":"看來不是營養問題，而是因為侵蝕體特有的能力，直接奪取了植物的生命力。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"혹시 이 침식체가 필요로 하는 게… 생명력이 아닌 다른 걸 수도 있을까요?","JPN":"もしかしてこの侵食体が必要としているのは……生命力ではなく他のものである可能性はないですか？","ENG":"Could it be that this C.O. needs... something other than life force?","TWN":"這個侵蝕體需要的，難道不是生命力，而是別的東西？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그런 이레귤러는 존재하지 않아. 적어도 지금까진.","JPN":"そんなイレギュラーは存在しない。少なくとも今までは。","ENG":"There are no such Irregulars. At least, none up until now.","TWN":"從未聽說過這種非典型侵蝕體。至少到目前為止沒有。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"처음엔 막연히 그 침식체가 모든 사건의 원흉이라 생각했어요.","JPN":"最初は漠然とその侵食体がすべての事件の元凶だと思いました。","ENG":"At first, I thought that C.O. was the root of all the incidents.","TWN":"最開始，我們都以為這個侵蝕體是所有事件的元兇。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"하지만 공사장에서 벌어진 집단 학살극이 그 녀석 짓이 아니라고 가정하면…","JPN":"でも工事現場で発生した集団虐殺が侵食体の仕業ではないとすると……","ENG":"But if we assume the mass slaughter at the construction site wasn't her doing.","TWN":"但如果排除她在工地上製造的那場集體屠殺……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이후에 녀석이 타깃으로 삼은 건 전부 카운터들뿐이죠.","JPN":"その侵食体がターゲットにしたのは全部カウンターだけってことになります。","ENG":"Her targets have all been Counters.","TWN":"她所選擇的目標，全都是制裁者。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"침식체가 어떤 동기를 갖고서 카운터만 노린 걸까요?","JPN":"侵食体は何の目的でカウンターだけを狙ったんですかね？","ENG":"Could the C.O. have had some kind of motive for targeting only Counters?","TWN":"她究竟是出於什麼動機，只獵殺制裁者呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"CRF겠군요.","JPN":"CRFでしょう。","ENG":"It must be the CRF.","TWN":"是CRF！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"침식 바이러스에 당한 환자들의 CRF가 소실된 건, 단순한 침식파 때문이 아니었어요.","JPN":"侵食ウイルスにやられた患者たちのCRFがなくなったのは、単純に侵食波が原因ではありませんでした。","ENG":"The CRF loss in patients affected by the Corruption virus wasn't simply due to Corruption rays.","TWN":"被侵蝕病毒感染的患者們之所以CRF消失，並不僅僅是因為侵蝕波。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"바이러스가 CRF를 흡수하고 있던 거죠.","JPN":"ウイルスがCRFを吸収していたんです。","ENG":"The virus has been absorbing the CRF.","TWN":"實際上，是病毒正在吸收CRF！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"침식체가 카운터의 CRF를 흡수한다니. 상당히 흥미로운… 이 아니라 끔찍한 일이네요.","JPN":"侵食体がカウンターのCRFを吸収するとは。とても興味深い……じゃない、酷いことですね。","ENG":"A C.O. absorbing the CRF from Counters... That's quite fascinating– I mean, horrifying.","TWN":"侵蝕體居然能吸收制裁者的CRF，真是相當有趣……不，應該說是可怕的事情。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그런 건 그림자도 할 수 없는데… 이터의 변종 같은 걸까요?","JPN":"そんな真似シャドウでもできないのに……イーターの変種みたいなものなんでしょうか？","ENG":"That's something even Shadows can't do... Could she be a variant of an Eater?","TWN":"這種能力就連暗影都無法做到……難道是永恆之金的變種？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"가정일 뿐이지만, 타깃을 이레귤러로 판단한 시점에서 가능성은 충분해요.","JPN":"まだ仮説に過ぎませんが、ターゲットをイレギュラーと判断した時点で可能性は十分です。","ENG":"It's just a hypothesis, but if we assume the target is an Irregular, it seems plausible enough.","TWN":"雖然只是推測，但既然它已經被判定為非正規類侵蝕體，那這種可能性就足夠存在。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"침식체가 다음으로 노리는 것도 카운터란 뜻일 테죠.","JPN":"侵食体が次に狙うターゲットもカウンターということです。","ENG":"That means the C.O.'s next target will also be a Counter.","TWN":"那侵蝕體接下來的目標，應該也是制裁者吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 십 분에 한 번 꼴로 사고를 치던 이전에 비하면 지금은 잠잠해요.","JPN":"でも10分に1回のペースで暴れていた時と比べると今は大人しいもんです。","ENG":"But compared to before, when accidents happened every few minutes, things have been quiet now.","TWN":"不過，相比之前每隔幾十分鐘就製造一次事故，她現在卻顯得異常安靜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"}}}}]`);export{e as default};